import React, { useState, useEffect, useCallback, useRef } from 'react';
import usePageTitle from '../hooks/usePageTitle';
import { api } from '../utils/api';
import s from './SystemHealthPage.module.css';

// ── Constants ────────────────────────────────────────────────────────────────
const REFRESH_INTERVAL = 15000;

const BOT_ACCENTS = {
  SHAWN: '#22d3ee',
  SHANE: '#a78bfa',
  NOVA: '#f59e0b',
  ALPHA: '#22d3ee',
  BETA: '#a78bfa',
  CRYPTO: '#f59e0b',
};

// ── Helpers ──────────────────────────────────────────────────────────────────
function statusColor(status) {
  if (!status) return '#6B7280';
  const st = String(status).toLowerCase();
  if (['healthy', 'active', 'running', 'ok', 'open', 'true', 'connected', 'online', 'up'].includes(st)) return '#22C55E';
  if (['degraded', 'warning', 'amber', 'partial', 'slow'].includes(st)) return '#F59E0B';
  if (['down', 'error', 'stopped', 'closed', 'false', 'disconnected', 'dead', 'red', 'critical', 'offline'].includes(st)) return '#EF4444';
  return '#6B7280';
}

function StatusDot({ status, size = 8 }) {
  const color = statusColor(status);
  const pulse = ['active', 'healthy', 'ok', 'connected', 'running', 'online', 'up'].includes(String(status).toLowerCase());
  return (
    <span
      className={`${s.dot} ${pulse ? s.dotPulse : ''}`}
      style={{ width: size, height: size, background: color, boxShadow: `0 0 ${size}px ${color}60` }}
    />
  );
}

function StatusBadge({ status, label }) {
  const color = statusColor(status);
  return (
    <span className={s.badge} style={{ color, background: `${color}15`, border: `1px solid ${color}30` }}>
      {label || status || 'unknown'}
    </span>
  );
}

function timeAgo(ts) {
  if (!ts) return 'never';
  const ms = typeof ts === 'number' && ts < 1e12 ? ts * 1000 : new Date(ts).getTime();
  const diff = Date.now() - ms;
  if (diff < 0) return 'just now';
  const secs = Math.floor(diff / 1000);
  if (secs < 60) return `${secs}s ago`;
  const mins = Math.floor(secs / 60);
  if (mins < 60) return `${mins}m ago`;
  const hrs = Math.floor(mins / 60);
  if (hrs < 24) return `${hrs}h ago`;
  return `${Math.floor(hrs / 24)}d ago`;
}

function formatTime(ts) {
  if (!ts) return '--';
  try {
    const ms = typeof ts === 'number' && ts < 1e12 ? ts * 1000 : ts;
    return new Date(ms).toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', second: '2-digit' });
  } catch { return '--'; }
}

function formatUptime(sec) {
  if (!sec || sec < 0) return '--';
  const d = Math.floor(sec / 86400);
  const h = Math.floor((sec % 86400) / 3600);
  const m = Math.floor((sec % 3600) / 60);
  if (d > 0) return `${d}d ${h}h ${m}m`;
  if (h > 0) return `${h}h ${m}m`;
  return `${m}m`;
}

function formatMs(ms) {
  if (ms == null) return '--';
  if (ms < 1) return '<1ms';
  if (ms < 1000) return `${Math.round(ms)}ms`;
  return `${(ms / 1000).toFixed(2)}s`;
}

function formatNumber(n) {
  if (n == null) return '--';
  if (n >= 1_000_000) return (n / 1_000_000).toFixed(1) + 'M';
  if (n >= 1_000) return (n / 1_000).toFixed(1) + 'K';
  return String(n);
}

function resourceStatus(pct) {
  if (pct == null) return 'unknown';
  if (pct < 70) return 'active';
  if (pct <= 85) return 'warning';
  return 'error';
}

function botHeartbeatAge(ts) {
  if (!ts) return 'error';
  const ms = typeof ts === 'number' && ts < 1e12 ? ts * 1000 : new Date(ts).getTime();
  const ageMin = (Date.now() - ms) / 60000;
  if (ageMin > 15) return 'error';
  if (ageMin > 5) return 'warning';
  return 'active';
}

// ── Error Boundary ───────────────────────────────────────────────────────────
class HealthErrorBoundary extends React.Component {
  constructor(props) { super(props); this.state = { error: null }; }
  static getDerivedStateFromError(error) { return { error }; }
  render() {
    if (this.state.error) {
      return (
        <div className={s.errorBoundary}>
          <h2>System Health Page Crashed</h2>
          <pre className={s.errorPre}>{this.state.error.toString()}</pre>
          <pre className={s.errorStack}>{this.state.error.stack}</pre>
        </div>
      );
    }
    return this.props.children;
  }
}

// ── Overall Status Header ────────────────────────────────────────────────────
function OverallStatusHeader({ controlHealth, lastRefresh, loading }) {
  const overallStatus = controlHealth?.status || (controlHealth ? 'healthy' : 'unknown');
  const killEnabled = controlHealth?.kill?.enabled || controlHealth?.kill_switch?.enabled || false;
  const canTrade = controlHealth?.can_trade ?? true;
  const gateway = controlHealth?.gateway || {};
  const gwStatus = gateway.connected ? 'connected' : gateway.connected === false ? 'disconnected' : 'unknown';
  const pulseColor = statusColor(overallStatus);

  return (
    <div className={s.statusStrip}>
      {/* Overall */}
      <div className={s.statusCard}>
        <div className={s.orbOuter} style={{ background: `${pulseColor}15` }}>
          <div className={s.orbInner} style={{ background: pulseColor, boxShadow: `0 0 14px ${pulseColor}60` }} />
        </div>
        <div>
          <div className={s.statusLabel} style={{ color: pulseColor }}>{overallStatus.toUpperCase()}</div>
          <div className={s.statusSub}>
            {loading ? 'Refreshing...' : `Updated ${lastRefresh ? timeAgo(lastRefresh) : '--'}`}
          </div>
        </div>
      </div>

      {/* Kill Switch */}
      <div className={s.statusCard} style={killEnabled ? { borderColor: '#EF444450', backgroundImage: 'linear-gradient(135deg, #0F1620, #EF444408)' } : undefined}>
        <StatusDot status={killEnabled ? 'error' : 'active'} size={12} />
        <div>
          <div className={s.statusLabel} style={{ color: killEnabled ? '#EF4444' : '#22C55E' }}>
            Kill Switch: {killEnabled ? 'ACTIVE' : 'OFF'}
          </div>
          <div className={s.statusSub}>{canTrade ? 'Trading enabled' : 'Trading halted'}</div>
        </div>
      </div>

      {/* Gateway */}
      <div className={s.statusCard}>
        <StatusDot status={gwStatus} size={12} />
        <div>
          <div className={s.statusLabel}>IBKR Gateway</div>
          <div className={s.statusSub} style={{ color: statusColor(gwStatus) }}>
            {gwStatus === 'connected' ? 'Port 4001 connected' : gwStatus === 'disconnected' ? 'Disconnected' : 'Unknown'}
          </div>
        </div>
      </div>

      {/* Trade Gate */}
      <div className={s.statusCard}>
        <StatusDot status={canTrade ? 'active' : 'error'} size={12} />
        <div>
          <div className={s.statusLabel} style={{ color: canTrade ? '#22C55E' : '#EF4444' }}>
            {canTrade ? 'CAN TRADE' : 'HALTED'}
          </div>
          <div className={s.statusSub}>{controlHealth?.reason || 'Gate check'}</div>
        </div>
      </div>
    </div>
  );
}

// ── Bot Heartbeat Cards ──────────────────────────────────────────────────────
function BotHeartbeatCards({ telemetry }) {
  // telemetry may have .bots as object or array, or top-level bot keys
  // Exclude paper/marketing bots (Layla, etc.) from system health display
  const PAPER_BOTS = new Set(['layla', 'paper', 'demo']);
  let bots = [];
  const raw = telemetry?.bots || telemetry;
  if (raw && typeof raw === 'object' && !Array.isArray(raw)) {
    for (const [key, val] of Object.entries(raw)) {
      if (key === 'bots' || key === 'timestamp' || key === 'status') continue;
      if (PAPER_BOTS.has(key.toLowerCase())) continue;
      if (typeof val === 'object' && val !== null && (val.status || val.last_heartbeat || val.payload)) {
        bots.push({
          name: val.bot || val.name || key.toUpperCase(),
          status: val.status || 'unknown',
          lastHeartbeat: val.last_heartbeat || val.lastHeartbeat,
          mode: val.payload?.mode || val.mode || '--',
          equity: val.payload?.equity?.current ?? val.equity?.current ?? val.equity ?? 0,
          positions: val.payload?.positions?.length ?? val.positions ?? 0,
          enabled: val.payload?.enabled ?? val.enabled ?? true,
        });
      }
    }
  }
  if (Array.isArray(raw)) {
    bots = raw.map(b => ({
      name: b.bot || b.name || 'UNKNOWN',
      status: b.status || 'unknown',
      lastHeartbeat: b.last_heartbeat || b.lastHeartbeat,
      mode: b.payload?.mode || b.mode || '--',
      equity: b.payload?.equity?.current ?? b.equity?.current ?? b.equity ?? 0,
      positions: b.payload?.positions?.length ?? b.positions ?? 0,
      enabled: b.payload?.enabled ?? b.enabled ?? true,
    }));
  }

  return (
    <div className={s.card}>
      <div className={s.sectionHeader}>Bot Heartbeats</div>
      {bots.length === 0 ? (
        <div className={s.emptyState}>No bot heartbeats received</div>
      ) : (
        <div className={s.botGrid}>
          {bots.map(bot => {
            const accent = BOT_ACCENTS[bot.name] || '#60A5FA';
            const hbStatus = botHeartbeatAge(bot.lastHeartbeat);
            const eqVal = typeof bot.equity === 'number' ? bot.equity : parseFloat(bot.equity) || 0;
            return (
              <div key={bot.name} className={s.botCard} style={{ borderTop: `2px solid ${accent}` }}>
                <div className={s.botHeader}>
                  <div className={s.botHeaderLeft}>
                    <StatusDot status={hbStatus} />
                    <span className={s.botName} style={{ color: accent }}>{bot.name}</span>
                  </div>
                  <StatusBadge status={bot.enabled ? hbStatus : 'stopped'} label={bot.mode} />
                </div>
                <div className={s.botStats}>
                  <div>
                    <div className={s.label}>Last Beat</div>
                    <div className={s.mono}>{formatTime(bot.lastHeartbeat)}</div>
                  </div>
                  <div>
                    <div className={s.label}>Age</div>
                    <div className={s.mono} style={{ color: hbStatus === 'error' ? '#EF4444' : hbStatus === 'warning' ? '#F59E0B' : undefined }}>
                      {timeAgo(bot.lastHeartbeat)}
                    </div>
                  </div>
                  <div>
                    <div className={s.label}>Equity</div>
                    <div className={s.mono}>${eqVal.toLocaleString()}</div>
                  </div>
                  <div>
                    <div className={s.label}>Positions</div>
                    <div className={s.mono}>{bot.positions}</div>
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}

// ── Database Health ──────────────────────────────────────────────────────────
function DatabaseHealth({ dbHealth }) {
  if (!dbHealth) return (
    <div className={s.card}>
      <div className={s.sectionHeader}>Database Health</div>
      <div className={s.emptyState}>Loading...</div>
    </div>
  );

  const status = dbHealth.status || dbHealth.health || 'unknown';
  const tables = dbHealth.tables || dbHealth.table_count || 0;
  const rows = dbHealth.rows || dbHealth.total_rows || dbHealth.row_count || 0;
  const dbSize = dbHealth.size || dbHealth.db_size || dbHealth.database_size || '--';
  const connPool = dbHealth.connections || dbHealth.pool || {};
  const activeConns = connPool.active || connPool.used || connPool.in_use || 0;
  const maxConns = connPool.max || connPool.total || connPool.pool_size || '--';
  const latency = dbHealth.latency_ms || dbHealth.query_latency_ms;
  const replication = dbHealth.replication || {};

  const metrics = [
    { label: 'Status', value: status, color: statusColor(status) },
    { label: 'Tables', value: tables, color: '#60A5FA' },
    { label: 'Total Rows', value: formatNumber(rows), color: '#22C55E' },
    { label: 'DB Size', value: dbSize, color: '#A78BFA' },
    { label: 'Connections', value: `${activeConns}/${maxConns}`, color: '#F59E0B' },
  ];
  if (latency != null) {
    metrics.push({ label: 'Query Latency', value: formatMs(latency), color: latency > 100 ? '#EF4444' : latency > 50 ? '#F59E0B' : '#22C55E' });
  }
  if (replication.status) {
    metrics.push({ label: 'Replication', value: replication.status, color: statusColor(replication.status) });
  }

  return (
    <div className={s.card}>
      <div className={s.sectionHeader}>
        <StatusDot status={status} size={8} />
        <span style={{ marginLeft: 8 }}>Database Health</span>
      </div>
      <div className={s.metricsGrid}>
        {metrics.map(m => (
          <div key={m.label} className={s.metricCell}>
            <div className={s.label}>{m.label}</div>
            <div className={s.metricValue} style={{ color: m.color }}>{m.value}</div>
          </div>
        ))}
      </div>
    </div>
  );
}

// ── API Latency Chart (pure CSS bar chart) ───────────────────────────────────
function LatencyChart({ latencyData }) {
  if (!latencyData) return (
    <div className={s.card}>
      <div className={s.sectionHeader}>API Latency</div>
      <div className={s.emptyState}>Loading...</div>
    </div>
  );

  // latencyData may be: { endpoints: [{path, avg_ms, p95_ms, p99_ms, count}] } or similar
  let endpoints = latencyData.endpoints || latencyData.routes || latencyData.latencies || [];
  if (!Array.isArray(endpoints) && typeof latencyData === 'object') {
    // Maybe it's a flat object { "/api/foo": { avg: 12, p95: 30 }, ... }
    endpoints = Object.entries(latencyData)
      .filter(([k]) => k.startsWith('/') || k.includes('api'))
      .map(([path, val]) => ({
        path,
        avg_ms: val.avg_ms ?? val.avg ?? val.mean ?? val.latency_ms ?? 0,
        p95_ms: val.p95_ms ?? val.p95 ?? 0,
        count: val.count ?? val.requests ?? 0,
      }));
  }

  // Sort by avg_ms descending, take top 10
  const sorted = [...endpoints].sort((a, b) => (b.avg_ms || 0) - (a.avg_ms || 0)).slice(0, 10);
  const maxMs = Math.max(...sorted.map(e => e.avg_ms || 0), 1);

  // Overall stats
  const avgOverall = latencyData.avg_ms ?? latencyData.overall_avg_ms;
  const p95Overall = latencyData.p95_ms ?? latencyData.overall_p95_ms;
  const totalReqs = latencyData.total_requests ?? latencyData.request_count;

  return (
    <div className={s.card}>
      <div className={s.sectionHeader}>API Latency</div>
      {(avgOverall != null || p95Overall != null || totalReqs != null) && (
        <div className={s.latencySummary}>
          {avgOverall != null && <span className={s.latencyStat}>Avg: <strong style={{ color: avgOverall > 200 ? '#EF4444' : avgOverall > 100 ? '#F59E0B' : '#22C55E' }}>{formatMs(avgOverall)}</strong></span>}
          {p95Overall != null && <span className={s.latencyStat}>P95: <strong style={{ color: p95Overall > 500 ? '#EF4444' : p95Overall > 200 ? '#F59E0B' : '#22C55E' }}>{formatMs(p95Overall)}</strong></span>}
          {totalReqs != null && <span className={s.latencyStat}>Requests: <strong>{formatNumber(totalReqs)}</strong></span>}
        </div>
      )}
      {sorted.length > 0 ? (
        <div className={s.latencyBars}>
          {sorted.map((ep, i) => {
            const pct = Math.max((ep.avg_ms / maxMs) * 100, 2);
            const barColor = ep.avg_ms > 500 ? '#EF4444' : ep.avg_ms > 200 ? '#F59E0B' : ep.avg_ms > 100 ? '#60A5FA' : '#22C55E';
            const path = ep.path || ep.endpoint || ep.route || `endpoint-${i}`;
            return (
              <div key={path} className={s.latencyRow}>
                <div className={s.latencyPath} title={path}>
                  {path.length > 30 ? '...' + path.slice(-28) : path}
                </div>
                <div className={s.latencyBarWrap}>
                  <div className={s.latencyBar} style={{ width: `${pct}%`, background: barColor }} />
                </div>
                <div className={s.latencyMs} style={{ color: barColor }}>
                  {formatMs(ep.avg_ms)}
                </div>
              </div>
            );
          })}
        </div>
      ) : (
        <div className={s.emptyState}>No latency data</div>
      )}
    </div>
  );
}

// ── Incident Log ─────────────────────────────────────────────────────────────
function IncidentLog({ incidents }) {
  if (!incidents) return (
    <div className={s.card}>
      <div className={s.sectionHeader}>Incident Log</div>
      <div className={s.emptyState}>Loading...</div>
    </div>
  );

  const list = incidents.incidents || incidents.events || (Array.isArray(incidents) ? incidents : []);

  function severityColor(sev) {
    if (!sev) return '#6B7280';
    const s = String(sev).toLowerCase();
    if (s === 'critical' || s === 'p0') return '#EF4444';
    if (s === 'error' || s === 'high' || s === 'p1') return '#F87171';
    if (s === 'warning' || s === 'medium' || s === 'p2') return '#F59E0B';
    if (s === 'info' || s === 'low' || s === 'p3') return '#60A5FA';
    return '#6B7280';
  }

  return (
    <div className={s.card}>
      <div className={s.sectionHeader}>Incident Log</div>
      {list.length === 0 ? (
        <div className={s.emptyState}>No incidents recorded</div>
      ) : (
        <div className={s.incidentList}>
          {list.slice(0, 15).map((inc, i) => {
            const sev = inc.severity || inc.level || inc.priority || 'info';
            const color = severityColor(sev);
            return (
              <div key={inc.id || i} className={s.incidentRow}>
                <div className={s.incidentDot} style={{ background: color }} />
                <div className={s.incidentContent}>
                  <div className={s.incidentTitle}>
                    <span style={{ color }}>{String(sev).toUpperCase()}</span>
                    <span className={s.incidentSep}> -- </span>
                    <span>{inc.title || inc.message || inc.description || inc.action || 'Incident'}</span>
                  </div>
                  {inc.detail && <div className={s.incidentDetail}>{inc.detail}</div>}
                  {(inc.service || inc.component) && (
                    <div className={s.incidentMeta}>{inc.service || inc.component}</div>
                  )}
                </div>
                <div className={s.incidentTime}>
                  {timeAgo(inc.timestamp || inc.created_at || inc.occurred_at)}
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}

// ── Job Queue Stats ──────────────────────────────────────────────────────────
function JobQueueStats({ queueStats }) {
  if (!queueStats) return (
    <div className={s.card}>
      <div className={s.sectionHeader}>Job Queue</div>
      <div className={s.emptyState}>Loading...</div>
    </div>
  );

  // Normalize: could be { queues: [...] } or { pending, running, completed, failed }
  const queues = queueStats.queues || [];
  const totals = {
    pending: queueStats.pending ?? queueStats.queued ?? 0,
    running: queueStats.running ?? queueStats.active ?? queueStats.in_progress ?? 0,
    completed: queueStats.completed ?? queueStats.done ?? queueStats.finished ?? 0,
    failed: queueStats.failed ?? queueStats.errors ?? 0,
    total: queueStats.total ?? 0,
  };

  const statCards = [
    { label: 'Pending', value: totals.pending, color: '#F59E0B', icon: '\u23F3' },
    { label: 'Running', value: totals.running, color: '#60A5FA', icon: '\u25B6' },
    { label: 'Completed', value: totals.completed, color: '#22C55E', icon: '\u2713' },
    { label: 'Failed', value: totals.failed, color: '#EF4444', icon: '\u2717' },
  ];

  return (
    <div className={s.card}>
      <div className={s.sectionHeader}>Job Queue</div>
      <div className={s.queueGrid}>
        {statCards.map(sc => (
          <div key={sc.label} className={s.queueCell}>
            <div className={s.queueCellValue} style={{ color: sc.color }}>
              {formatNumber(sc.value)}
            </div>
            <div className={s.label}>{sc.label}</div>
          </div>
        ))}
      </div>
      {queues.length > 0 && (
        <div className={s.queueTable}>
          <table className={s.table}>
            <thead>
              <tr>
                {['Queue', 'Pending', 'Running', 'Failed', 'Status'].map(h => (
                  <th key={h}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {queues.map((q, i) => (
                <tr key={q.name || q.queue || i}>
                  <td className={s.queueName}>{q.name || q.queue || `queue-${i}`}</td>
                  <td className={s.mono}>{q.pending ?? q.queued ?? 0}</td>
                  <td className={s.mono}>{q.running ?? q.active ?? 0}</td>
                  <td className={s.mono} style={{ color: (q.failed || 0) > 0 ? '#EF4444' : undefined }}>{q.failed ?? 0}</td>
                  <td><StatusBadge status={q.status || 'active'} /></td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

// ── Grid Worker Health ───────────────────────────────────────────────────────
